INSERT INTO `v1_eb2e4a41888c8abe85cbb691c8c1e18752332384ad7191a24cb6c07e9cf2a6f0` VALUES (1, 24001, 0.0, 10040, "リン", 0.0, 24, 0.0, "2030/12/17 14:59:59", 102601, "2020/04/30 12:00:00", 1, 0, "あたしだって\nやるときはやるよ！");
INSERT INTO `v1_eb2e4a41888c8abe85cbb691c8c1e18752332384ad7191a24cb6c07e9cf2a6f0` VALUES (1, 24002, 0.0, 10040, "リン", 0.0, 24, 0.0, "2030/12/17 14:59:59", 102601, "2020/04/30 12:00:00", 1, 1, "ふぅ…\nこれであたしの仕事は\n終わりだね");
INSERT INTO `v1_eb2e4a41888c8abe85cbb691c8c1e18752332384ad7191a24cb6c07e9cf2a6f0` VALUES (1, 24003, 0.0, 10040, "リン", 0.0, 24, 0.0, "2030/12/17 14:59:59", 102601, "2020/04/30 12:00:00", 1, 2, "終わった終わった\n一人でもなんとか\nなるもんだね");
INSERT INTO `v1_eb2e4a41888c8abe85cbb691c8c1e18752332384ad7191a24cb6c07e9cf2a6f0` VALUES (2, 24004, 0.0, 10040, "リン", 0.0, 24, 0.0, "2030/12/17 14:59:59", 102601, "2020/04/30 12:00:00", 2, 3, "やったね！\nこれでようやく\nサボれるよ…");
INSERT INTO `v1_eb2e4a41888c8abe85cbb691c8c1e18752332384ad7191a24cb6c07e9cf2a6f0` VALUES (1, 24005, 0.0, 10040, "リン", 0.0, 24, 0.0, "2030/12/17 14:59:59", 102601, "2020/04/30 12:00:00", 1, 4, "チーズが欲しいなら\nきちんと働いて\n買いに来なよ");
INSERT INTO `v1_eb2e4a41888c8abe85cbb691c8c1e18752332384ad7191a24cb6c07e9cf2a6f0` VALUES (2, 24006, 0.0, 10040, "リン", 0.0, 24, 0.0, "2030/12/17 14:59:59", 102601, "2020/04/30 12:00:00", 2, 5, "あたしを敵に回した\n恐ろしさ\n思い知ったか！");
INSERT INTO `v1_eb2e4a41888c8abe85cbb691c8c1e18752332384ad7191a24cb6c07e9cf2a6f0` VALUES (2, 24007, 0.0, 10040, "リン", 0.0, 24, 0.0, "2030/12/17 14:59:59", 102601, "2020/04/30 12:00:00", 2, 6, "あたしも意外と\nやるもんでしょ？");
INSERT INTO `v1_eb2e4a41888c8abe85cbb691c8c1e18752332384ad7191a24cb6c07e9cf2a6f0` VALUES (4, 24008, 0.0, 10040, "リン", 0.0, 24, 0.0, "2030/12/17 14:59:59", 102601, "2020/04/30 12:00:00", 4, 7, "疲れた…\nねずみの逃げ足\n速すぎるよ…");
INSERT INTO `v1_eb2e4a41888c8abe85cbb691c8c1e18752332384ad7191a24cb6c07e9cf2a6f0` VALUES (4, 24009, 0.0, 10040, "リン", 0.0, 24, 0.0, "2030/12/17 14:59:59", 102601, "2020/04/30 12:00:00", 4, 8, "このままじゃ\nまっひ～に\n叱られちゃうよ");
INSERT INTO `v1_eb2e4a41888c8abe85cbb691c8c1e18752332384ad7191a24cb6c07e9cf2a6f0` VALUES (4, 24010, 0.0, 10040, "リン", 0.0, 24, 0.0, "2030/12/17 14:59:59", 102601, "2020/04/30 12:00:00", 4, 9, "まじめに\nやったんだけどな…\n悔しいな～");
INSERT INTO `v1_eb2e4a41888c8abe85cbb691c8c1e18752332384ad7191a24cb6c07e9cf2a6f0` VALUES (4, 24011, 0.0, 10040, "リン", 0.0, 24, 0.0, "2030/12/17 14:59:59", 102601, "2020/04/30 12:00:00", 4, 10, "やられた…\nねずみって意外と\nてごわいね");
INSERT INTO `v1_eb2e4a41888c8abe85cbb691c8c1e18752332384ad7191a24cb6c07e9cf2a6f0` VALUES (4, 24012, 0.0, 10040, "リン", 0.0, 24, 0.0, "2030/12/17 14:59:59", 102601, "2020/04/30 12:00:00", 4, 11, "おのれ～\nあたしのチーズを\n盗みやがって～！");
INSERT INTO `v1_eb2e4a41888c8abe85cbb691c8c1e18752332384ad7191a24cb6c07e9cf2a6f0` VALUES (1, 24013, 1.81, 10040, "リン", 0.0, 24, 0.0, "2030/12/17 14:59:59", 102601, "2020/04/30 12:00:00", 4, 12, "疲れた…\nけど、次こそは\n守り抜くよ…");
